var raw = $input.first().json;
var body = raw.body || raw;
var data = body.data || body;
var tenantId = String(body.tenantId || data.tenantId || '');

function esc(v) {
  return v == null ? '' : String(v).replace(/'/g, "''");
}

const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(tenantId)) {
  throw new Error('Invalid tenantId');
}

var whereParts = ["p.tenant_id = '" + esc(tenantId) + "'"];

if (data.clientFinalId && data.clientFinalId.trim()) {
  whereParts.push("p.client_final_id = '" + esc(data.clientFinalId) + "'");
}
if (data.annee !== undefined && data.annee !== null && data.annee !== '') {
  whereParts.push("p.annee = " + parseInt(data.annee));
}
if (data.statut && data.statut.trim()) {
  whereParts.push("p.statut = '" + esc(data.statut) + "'");
}

var query = "SELECT p.*, c.raison_sociale as client_raison_sociale, c.nom as client_nom, c.prenom as client_prenom FROM previsionnels p LEFT JOIN client_finals c ON p.client_final_id = c.id WHERE " + whereParts.join(' AND ') + " ORDER BY p.updated_at DESC;";

return [{json: {query: query}}];

var rows = $input.all().map(function(i) { return i.json; }).filter(function(i) { return i.id; });
var items = rows.map(function(row) {
  var clientLabel = row.client_raison_sociale || ((row.client_nom || '') + ' ' + (row.client_prenom || '')).trim() || null;
  return {
    id: row.id,
    tenantId: row.tenant_id,
    clientFinalId: row.client_final_id || null,
    clientLabel: clientLabel,
    nom: row.nom || 'Prévisionnel',
    description: row.description || null,
    annee: Number(row.annee || 0),
    statut: row.statut || 'brouillon',
    caAnnuel: Number(row.ca_annuel || 0),
    chargesAnnuelles: Number(row.charges_annuelles || 0),
    resultatExploitation: Number(row.resultat_exploitation || 0),
    seuilRentabilite: Number(row.seuil_rentabilite || 0),
    tresorerieFinale: Number(row.tresorerie_finale || 0),
    createdAt: row.created_at,
    updatedAt: row.updated_at
  };
});

return [{json: {success: true, count: items.length, data: items}}];
